# REST: multiple endpoints
GET /users/1
GET /users/1/posts

# GraphQL: single endpoint, precise query
query {
  user(id: 1) {
    name
    email
    posts {
      title
    }
  }
}

// Consistent error format
HTTP/1.1 400 Bad Request
{
  "error": {
    "code": "VALIDATION_ERROR",
    "message": "Email is required",
    "field": "email"
  }
}

// Paginated response
GET /v1/users?page=2&limit=20
{
  "data": [...],
  "meta": {
    "page": 2,
    "total": 156,
    "hasMore": true
  }
}
